#define INF 99999
int map[SIZE][SIZE]; // The graph, initialized to be INF
int len[SIZE];
int visit[SIZE];
int n; // Number of vertices
int m; // Number of edges
int dijkstra(int from, int to) {
    int i;
    for (i = 1; i <= n; i++) {
        visit[i] = 0;
        len[i] = map[from][i];
    }
    int j;
    for (i = 1; i < n; ++i) {
        int min = INF;
        int pos;
        for (j = 1; j <= n; ++j) {
            if (!visit[j] && min > len[j]) {
                pos = j;
                min = len[j];
            }
        }
        /* blank 1: mark visited */
        for (j = 1; j <= n; ++j) {
            /* blank 2: relaxation condition and update */
        }
    }
    return len[to];
}
