int dfs(Virus V, int node, int path[], int *pathLen, int bestChain[], int *bestLen) {
    path[(*pathLen)++] = node;
    if (V->var[node][0] == 0) {
        if (*pathLen > *bestLen || (*pathLen == *bestLen && comparePath(path, bestChain, *pathLen) < 0)) {
            *bestLen = *pathLen;
            for (int i = 0; i < *pathLen; i++) bestChain[i] = path[i];
        }
    } else {
        for (int j = 1; j <= V->var[node][0]; j++) {
            dfs(V, V->var[node][j], path, pathLen, bestChain, bestLen);
        }
    }
    (*pathLen)--;
}

int LVC(Virus V, int Chain[]) {
    int inDeg[MAXN] = {0};
    for (int i = 0; i < V->n; i++)
        for (int j = 1; j <= V->var[i][0]; j++)
            inDeg[V->var[i][j]]++;
    int source = -1;
    for (int i = 0; i < V->n; i++)
        if (inDeg[i] == 0) { source = i; break; }
    int path[MAXN], pathLen = 0, bestLen = 0;
    dfs(V, source, path, &pathLen, Chain, &bestLen);
    return bestLen;
}

