Tree BuildTree(int inorder[], int postorder[], int N)
{
    int i;
    Tree tree;
    if (N == 0) return NULL;
    tree = malloc(sizeof(struct TreeNode));
    tree->Element = postorder[N - 1];
    tree->Left = NULL;
    tree->Right = NULL;
    for (i = 0; i < N; i++) {
        if (inorder[i] == tree->Element) {
            break;
        }
    }
    if (i == 0) {
        tree->Left = NULL;
    } else {
        tree->Left = BuildTree(inorder, postorder, i);
    }
    if (i == N - 1) {
        tree->Right = NULL;
    } else {
        tree->Right = BuildTree(inorder + i + 1, postorder + i, N - i - 1);
    }
    return tree;
}
